#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <cmath>
#include "lodepng.h"
#include "cJSON.h"

static char* read_file(const char* path){
    FILE* f=fopen(path,"rb");
    if(!f) return nullptr;
    fseek(f,0,SEEK_END); long n=ftell(f); fseek(f,0,SEEK_SET);
    char* buf=(char*)malloc(n+1);
    if(fread(buf,1,n,f)!=(size_t)n){ fclose(f); free(buf); return nullptr; }
    buf[n]=0; fclose(f); return buf;
}

static void load_matrix(cJSON* arr, std::vector<std::vector<double>>& m){
    cJSON* row; 
    cJSON_ArrayForEach(row,arr){
        std::vector<double> r;
        cJSON* v;
        cJSON_ArrayForEach(v,row) r.push_back(v->valuedouble);
        m.push_back(r);
    }
}
static void load_vector(cJSON* arr, std::vector<double>& m){
    cJSON* v;
    cJSON_ArrayForEach(v,arr) m.push_back(v->valuedouble);
}

struct Layer{ std::vector<std::vector<double>> w; std::vector<double> b; };

static std::vector<double> linear(const Layer& L, const std::vector<double>& x){
    std::vector<double> out(L.b.size());
    for(size_t i=0;i<L.w.size();++i){
        double s=L.b[i];
        const std::vector<double>& row=L.w[i];
        for(size_t j=0;j<row.size();++j) s+=row[j]*x[j];
        out[i]=s;
    }
    return out;
}
static void relu(std::vector<double>& x){ for(double& v:x) if(v<0) v=0; }

int main(int argc,char** argv){
    if(argc<3){ fprintf(stderr,"usage: %s weights.json image.png\n",argv[0]); return 1; }
    char* txt=read_file(argv[1]);
    if(!txt){ fprintf(stderr,"cannot read weights\n"); return 1; }
    cJSON* root=cJSON_Parse(txt);
    if(!root){ fprintf(stderr,"bad json\n"); return 1; }
    Layer in,hid,out;
    load_matrix(cJSON_GetObjectItem(cJSON_GetObjectItem(root,"input_layer"),"weight"),in.w);
    load_vector(cJSON_GetObjectItem(cJSON_GetObjectItem(root,"input_layer"),"bias"),in.b);
    load_matrix(cJSON_GetObjectItem(cJSON_GetObjectItem(root,"hidden_layer"),"weight"),hid.w);
    load_vector(cJSON_GetObjectItem(cJSON_GetObjectItem(root,"hidden_layer"),"bias"),hid.b);
    load_matrix(cJSON_GetObjectItem(cJSON_GetObjectItem(root,"output_layer"),"weight"),out.w);
    load_vector(cJSON_GetObjectItem(cJSON_GetObjectItem(root,"output_layer"),"bias"),out.b);
    cJSON_Delete(root); free(txt);

    std::vector<unsigned char> image;
    unsigned width,height;
    unsigned err=lodepng::decode(image,width,height,argv[2],LCT_GREY,8);
    if(err){ fprintf(stderr,"png error %s\n",lodepng_error_text(err)); return 1; }

    std::vector<double> x(width*height);
    for(size_t i=0;i<x.size();++i){
        double p=image[i]/255.0;
        x[i]=(p-0.1307)/0.3081;
    }
    std::vector<double> h1=linear(in,x); relu(h1);
    std::vector<double> h2=linear(hid,h1); relu(h2);
    std::vector<double> logits=linear(out,h2);
    int best=0; for(size_t i=1;i<logits.size();++i) if(logits[i]>logits[best]) best=i;
    printf("%d\n",best);
    return 0;
}
